// Precomputed per-frame bright-object mask (Earth, Moon, Sun, planets) for the
// starfield, so stars never render over a lit body. Baked offline (32x18 luma
// threshold + 1-cell dilation, LSB-first bit-packed) instead of sampling the
// #view canvas at runtime -- that read taints the canvas under file:// and
// silently disables masking. Covers star-phase frames [f0..f1]; 72 bytes/frame.
window.__STAR_MASK = { w: 32, h: 18, f0: 675, f1: 1347, bpf: 72, b64: "" };
